1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	function keyOf([x, y]: Cell): string {
10	  return `${x},${y}`;
11	}
12	
13	function neighborsOf([x, y]: Cell): Cell[] {
14	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	}
16	
17	function countLiveNeighbors(cell: Cell, liveSet: Set<string>): number {
18	  return neighborsOf(cell).filter((n) => liveSet.has(keyOf(n))).length;
19	}
20	
21	function candidateCells(liveCells: Cell[]): Cell[] {
22	  const seen = new Map<string, Cell>();
23	  for (const cell of liveCells) {
24	    for (const candidate of [cell, ...neighborsOf(cell)]) {
25	      seen.set(keyOf(candidate), candidate);
26	    }
27	  }
28	  return [...seen.values()];
29	}
30	
31	export function nextGeneration(liveCells: Cell[]): Cell[] {
32	  const liveSet = new Set(liveCells.map(keyOf));
33	  return candidateCells(liveCells).filter((cell) => {
34	    const n = countLiveNeighbors(cell, liveSet);
35	    return n === 3 || (n === 2 && liveSet.has(keyOf(cell)));
36	  });
37	}
