function candidateCells(liveCells: Cell[]): Cell[] {
  const seen = new Map<string, Cell>();
  for (const live of liveCells) {
    seen.set(keyOf(live), live);
    for (const neighbor of neighborsOf(live)) {
      seen.set(keyOf(neighbor), neighbor);
    }
  }
  return [...seen.values()];
}

function isAliveNext(cell: Cell, liveSet: Set<string>): boolean {
  const liveNeighbors = countLiveNeighbors(cell, liveSet);
  return liveNeighbors === 3 || (liveNeighbors === 2 && liveSet.has(keyOf(cell)));
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(keyOf));
  return candidateCells(liveCells).filter((cell) => isAliveNext(cell, liveSet));
}
